import{_ as i,o as s,c as t,a2 as a}from"./chunks/framework.CKCxdkvf.js";const k=JSON.parse('{"title":"ADR-036 — ?-chip cross-screen pattern: click navigates, hover tooltip on desktop","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-036.md","filePath":"adr/ADR-036.md"}'),n={name:"adr/ADR-036.md"};function o(l,e,h,p,c,r){return s(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="adr-036-—-chip-cross-screen-pattern-click-navigates-hover-tooltip-on-desktop" tabindex="-1">ADR-036 — <code>?</code>-chip cross-screen pattern: click navigates, hover tooltip on desktop <a class="header-anchor" href="#adr-036-—-chip-cross-screen-pattern-click-navigates-hover-tooltip-on-desktop" aria-label="Permalink to &quot;ADR-036 — `?`-chip cross-screen pattern: click navigates, hover tooltip on desktop&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-05-07 Closes · RFC-011 (with ADR-034, ADR-035) TA anchor · §components / primary-route-pages Related · PRD-008, ADR-018 (mobile-first), ADR-024 (deep-link URLs)</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>PRD-008 promises a <code>?</code> chip next to every technical label in the Orrery HUD that names a concept covered in <code>/science</code>. The chips appear on <code>/plan</code> (porkchop axes), <code>/fly</code> (HUD rows), <code>/missions</code> FLIGHT tab (C3, V∞, TLI, TMI, TCM, OI, total ∆v), <code>/explore</code> planet panels (Keplerian element rows), <code>/earth</code> (orbit-altitude regimes), <code>/moon</code> and <code>/mars</code> (trajectory-type narrative). ~30 attachment points total.</p><p>RFC-011 OQ-3 asked how the <code>?</code> chip behaves: click only, click + hover tooltip, or click into a popover modal.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><h3 id="behaviour-rfc-oq-3-—-option-b" tabindex="-1">Behaviour (RFC OQ-3 — Option B) <a class="header-anchor" href="#behaviour-rfc-oq-3-—-option-b" aria-label="Permalink to &quot;Behaviour (RFC OQ-3 — Option B)&quot;">​</a></h3><p>The <code>?</code> chip:</p><ul><li><strong>Renders</strong> as a 14×14 px circle with a question-mark glyph. Min hit area 24×24 px (smaller than ADR-018&#39;s 44 px primary touch baseline because chips sit inline next to HUD labels and would crowd out content otherwise).</li><li><strong>On hover (desktop only)</strong>: shows the section&#39;s <code>intro_sentence</code> (≤ 80 chars) as a <code>title</code> attribute / native browser tooltip. No custom popover JS, no portal, no positioning math.</li><li><strong>On click / tap (both desktop and mobile)</strong>: navigates to <code>/science/[tab]/[section]</code>. Full SvelteKit page navigation; the user lands on the static-prerendered section page.</li><li><strong>No popover modal</strong>: rejected per RFC-011 OQ-3 Option C. A modal on mobile click is exactly the context-loss anti-pattern PRD-008 wants to avoid.</li></ul><h3 id="component-src-lib-components-sciencechip-svelte" tabindex="-1">Component (<code>src/lib/components/ScienceChip.svelte</code>) <a class="header-anchor" href="#component-src-lib-components-sciencechip-svelte" aria-label="Permalink to &quot;Component (`src/lib/components/ScienceChip.svelte`)&quot;">​</a></h3><p>Single reusable component with props <code>{ tab: string, section: string, hoverTitle?: string }</code>:</p><div class="language-svelte vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">svelte</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">a</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  href</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">={</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">`${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">base</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}/science/${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">tab</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}/${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">section</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  class</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;science-chip&quot;</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  title</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">={hoverTitle </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">??</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  aria-label</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">={</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">`Learn about ${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">section</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;?&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">a</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>CSS: 14 px circle, white-50 fill, white-90 question mark, 1 px border, 24 px hit area via padding. Hover/focus states bump to teal (<code>#4ecdc4</code>). Matches the mission LEARN tab link aesthetic.</p><h3 id="typography-placement-contract" tabindex="-1">Typography + placement contract <a class="header-anchor" href="#typography-placement-contract" aria-label="Permalink to &quot;Typography + placement contract&quot;">​</a></h3><p>The chip lives <strong>inline</strong> with its label, not on a separate line. Examples:</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">dt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;C3 &lt;</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">ScienceChip</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tab</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;propulsion&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> section</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;c3&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">dt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">span</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> class</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;hud-key&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;∆V HELIO &lt;</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">ScienceChip</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tab</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;propulsion&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> section</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;dv&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">span</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>Keeps the label as a single visual unit; the chip reads as &quot;tap for definition&quot; punctuation.</p><h3 id="internationalisation" tabindex="-1">Internationalisation <a class="header-anchor" href="#internationalisation" aria-label="Permalink to &quot;Internationalisation&quot;">​</a></h3><p>The <code>hoverTitle</code> prop comes from the section&#39;s <code>intro_sentence</code> (already localised per ADR-017). No additional i18n keys required for the chip itself; the chip&#39;s <code>aria-label</code> uses the section ID directly.</p><p>For surfaces where the label is not yet i18n&#39;d (e.g. <code>/earth</code> LEO/MEO/GEO/HEO regime labels, <code>/moon</code> and <code>/mars</code> mission_type strings), Phase 2 work adds the i18n keys as a prerequisite — chip placement waits on label internationalisation.</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p><strong>Positive:</strong> Zero new component infrastructure beyond <code>ScienceChip.svelte</code>. Hover tooltip is free (native <code>title</code>). Mobile UX preserves single-flow — no modal context-loss. Deep-linkable URLs (<code>/science/[tab]/[section]</code>) match the rest of the app&#39;s URL contract per ADR-024. Reuses the existing LEARN-tab link aesthetic, no new design tokens.</p><p><strong>Negative:</strong> Native <code>title</code> tooltips are minimally styled and time out on long hovers — not a polished tooltip experience on desktop, but the click-navigate is the primary interaction so the tooltip is a desktop convenience, not a contract. ~30 attachment points across 7 routes is meaningful integration scope (Phase 2).</p><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><ul><li>Component: <code>src/lib/components/ScienceChip.svelte</code>.</li><li>Phase 1 (this ADR&#39;s scope): the chip component + the &quot;see in app&quot; inverse chip on the <code>/science</code> side (<code>SeeInAppChip.svelte</code> linking back to existing routes).</li><li>Phase 2 (separate batch): wire ~30 chip placements across <code>/plan</code>, <code>/fly</code>, <code>/missions</code>, <code>/explore</code>, <code>/earth</code>, <code>/moon</code>, <code>/mars</code>. Tracked under issue #39 Phase D.</li><li>Section ID stability: the chip&#39;s <code>tab</code> + <code>section</code> props rely on the URL contract from PRD-008 §scope. Section IDs are an enum in <code>science-section.schema.json</code>; renaming a section is a breaking change and requires migrating chip placements in lockstep.</li></ul>',25)])])}const E=i(n,[["render",o]]);export{k as __pageData,E as default};
